const i=`{% block sw_promotion_v2_settings_trigger %} <div class="sw-promotion-v2-settings-trigger-settings"> {% block sw_promotion_v2_settings_trigger_description %} <sw-promotion-v2-wizard-description class="sw-promotion-v2-settings-trigger-settings__description" > {{ $t('sw-promotion-v2.detail.discounts.wizard.shipping-discount.description') }} </sw-promotion-v2-wizard-description> {% endblock %} {% block sw_promotion_v2_settings_trigger_radio_switch %} <mt-switch v-model="useTrigger" class="sw-promotion-v2-settings-trigger-settings__use-trigger" :label="$t('sw-promotion-v2.detail.discounts.settings.trigger.labelUseTrigger')" /> {% endblock %} {% block sw_promotion_v2_settings_trigger_container %} <sw-container v-if="useTrigger"> {% block sw_promotion_v2_settings_trigger_select_trigger_type %} <mt-select v-model="triggerType" class="sw-promotion-v2-settings-trigger-settings__trigger-type" :label="$t('sw-promotion-v2.detail.discounts.settings.trigger.labelNumberOfTriggers')" :disabled="!acl.can('promotion.editor')" :options="triggerOptions" /> {% endblock %} {% block sw_promotion_v2_settings_trigger_rule_selection_selection %} <sw-select-rule-create v-model:rules="discount.discountRules" local-mode class="sw-promotion-v2-settings-trigger-settings__rule-selection" :rule-filter="ruleCriteria" :rule-scope="['cart']" :label="$t('sw-promotion-v2.detail.discounts.settings.ruleSelection.labelSelection')" :placeholder="$t('sw-promotion-v2.detail.discounts.settings.ruleSelection.placeholderSelection')" :disabled="!acl.can('promotion.editor')" /> {% endblock %} </sw-container> {% endblock %} </div> {% endblock %}`,{Criteria:t}=Shopware.Data,s={template:i,inject:["acl"],props:{discount:{type:Object,required:!0}},data(){return{useTrigger:this.discount.discountRules.length>0,triggerType:"single"}},computed:{ruleCriteria(){return new t(1,25).addSorting(t.sort("name","ASC",!1))},triggerOptions(){return this.getTriggerSelection().map(e=>({id:e.value,value:e.value,label:e.display}))}},watch:{"discount.discountRules"(e){this.discount.considerAdvancedRules=e.length>0}},methods:{getTriggerSelection(){const e="sw-promotion-v2.detail.discounts.settings.trigger.triggerType";return[{value:"single",display:this.$t(`${e}.displaySingleTrigger`),disabled:!1},{value:"multi",display:this.$t(`${e}.displayMultiTrigger`),disabled:!0}]}}};export{s as default};
